'use client'

import { createContext, type KeyboardEvent, type ReactNode } from 'react'
import { useSignalEffect, useSignals } from '@cascivo/core'
import { usePopover, type UsePopoverReturn } from '../popover/use-popover'
import styles from './menu.module.css'

const MenuContext = createContext<UsePopoverReturn | null>(null)

export interface MenuProps {
  children: ReactNode
}

function MenuPanelInner({ ctx, children }: { ctx: UsePopoverReturn; children: ReactNode }) {
  useSignals()
  const { popoverRef, anchorName, isOpen } = ctx

  useSignalEffect(() => {
    if (!isOpen.value) return
    const panel = popoverRef.current
    if (!panel) return
    const first = panel.querySelector<HTMLElement>('[role="menuitem"]:not([aria-disabled="true"])')
    first?.focus()
  })

  return (
    <div
      ref={popoverRef as React.RefObject<HTMLDivElement>}
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-ignore — popover is a valid HTML attribute not yet in React types
      popover="auto"
      role="menu"
      data-state={isOpen.value ? 'open' : 'closed'}
      style={{ positionAnchor: anchorName } as React.CSSProperties}
      className={styles.panel}
    >
      {children}
    </div>
  )
}

function MenuPanel({ children }: { children: ReactNode }) {
  return (
    <MenuContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('MenuPanel must be inside <Menu>')
        return <MenuPanelInner ctx={ctx}>{children}</MenuPanelInner>
      }}
    </MenuContext.Consumer>
  )
}

export function Menu({ children }: MenuProps) {
  const popover = usePopover()
  const childArray = Array.isArray(children) ? children : [children]
  const [trigger, ...items] = childArray
  return (
    <MenuContext.Provider value={popover}>
      {trigger}
      <MenuPanel>{items}</MenuPanel>
    </MenuContext.Provider>
  )
}

export interface MenuTriggerProps {
  children: ReactNode
  'aria-label'?: string
}

function MenuTriggerInner({
  ctx,
  children,
  'aria-label': ariaLabel,
}: {
  ctx: UsePopoverReturn
  children: ReactNode
  'aria-label'?: string
}) {
  useSignals()
  const { triggerRef, toggle, anchorName, isOpen } = ctx
  return (
    <button
      ref={triggerRef as React.RefObject<HTMLButtonElement>}
      type="button"
      aria-haspopup="menu"
      aria-expanded={isOpen.value}
      aria-label={ariaLabel}
      style={{ anchorName } as React.CSSProperties}
      onClick={toggle}
      className={styles.trigger}
    >
      {children}
    </button>
  )
}

export function MenuTrigger({ children, 'aria-label': ariaLabel }: MenuTriggerProps) {
  return (
    <MenuContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('MenuTrigger must be inside <Menu>')
        return (
          <MenuTriggerInner ctx={ctx} {...(ariaLabel !== undefined && { 'aria-label': ariaLabel })}>
            {children}
          </MenuTriggerInner>
        )
      }}
    </MenuContext.Consumer>
  )
}

export interface MenuItemProps {
  children: ReactNode
  onSelect: () => void
  disabled?: boolean
}

export function MenuItem({ children, onSelect, disabled }: MenuItemProps) {
  return (
    <MenuContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('MenuItem must be inside <Menu>')
        const { close } = ctx
        function handleClick() {
          if (disabled) return
          onSelect()
          close()
        }
        function handleKeyDown(e: KeyboardEvent) {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault()
            handleClick()
          }
          if (e.key === 'ArrowDown') {
            e.preventDefault()
            const next = (e.currentTarget as HTMLElement).nextElementSibling as HTMLElement | null
            next?.focus()
          }
          if (e.key === 'ArrowUp') {
            e.preventDefault()
            const prev = (e.currentTarget as HTMLElement)
              .previousElementSibling as HTMLElement | null
            prev?.focus()
          }
        }
        return (
          <div
            role="menuitem"
            tabIndex={disabled ? -1 : 0}
            aria-disabled={disabled}
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            className={styles.item}
          >
            {children}
          </div>
        )
      }}
    </MenuContext.Consumer>
  )
}

export function MenuSeparator() {
  return <div role="separator" className={styles.separator} />
}

@layer cascivo.component {
  .trigger {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-block-size: 1.5rem; /* 24px — WCAG 2.5.8 target size */
    min-inline-size: 1.5rem;
    padding: var(--cascivo-space-1);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    color: inherit;
    cursor: pointer;

    &:hover {
      background: var(--cascivo-color-active-bg);
    }

    &:focus-visible {
      outline: var(--cascivo-focus-ring);
      outline-offset: 2px;
    }
  }

  .panel {
    position: fixed;
    inset: auto;
    margin: 0;
    padding: var(--cascivo-space-1);
    min-width: 10rem;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    @supports (anchor-name: --a) {
      position-try-fallbacks:
        flip-block,
        flip-inline,
        flip-block flip-inline;
      inset-block-start: anchor(end);
      inset-inline-start: anchor(start);
    }

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    padding: var(--cascivo-space-2) var(--cascivo-space-3);
    border-radius: var(--cascivo-radius-item);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;
    user-select: none;
    outline: none;

    &:hover,
    &:focus-visible {
      background: var(--cascivo-color-bg-subtle);
    }

    &[aria-disabled='true'] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .separator {
    height: 1px;
    margin-block: var(--cascivo-space-1);
    background: var(--cascivo-color-border);
  }
}
